import { useState } from "react";

const WINNING_LINES = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],
  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],
  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function emptyBoard() {
  return [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ];
}

function findWinner(board) {
  for (const [a, b, c] of WINNING_LINES) {
    if (
      board[a[0]][a[1]] &&
      board[a[0]][a[1]] === board[b[0]][b[1]] &&
      board[a[0]][a[1]] === board[c[0]][c[1]]
    ) {
      return board[a[0]][a[1]];
    }
  }

  return null;
}

export default function TicTacToe() {
  const [board, setBoard] = useState(emptyBoard());
  const [turn, setTurn] = useState("X");

  const winner = findWinner(board);

  function play(row, col) {
    if (board[row][col] || winner) return;

    const nextBoard = board.map(row => [...row]);
    nextBoard[row][col] = turn;

    setBoard(nextBoard);
    setTurn(turn === "X" ? "O" : "X");
  }

  function reset() {
    setBoard(emptyBoard());
    setTurn("X");
  }

  return (
    <main>
      <h1>Tic Tac Toe</h1>

      <p>{winner ? `${winner} wins!` : `Turn: ${turn}`}</p>

      <table
        style={{
        //   margin: "0 auto",
        //   borderCollapse: "collapse",
        //   fontFamily: "monospace",
        //   fontSize: "2rem",
        }}
      >
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  onClick={() => play(r, c)}
                  style={{
                    width: "2em",
                    height: "2em",
                    textAlign: "center",
                    cursor: "pointer",
                    border: "1px solid",
                    userSelect: "none",
                  }}
                >
                  {cell || " "}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>

      <p>
        <button onClick={reset}>Play Again</button>
      </p>
    </main>
  );
}
